<?php
namespace App\Models\Customers; use App\Models\Company; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\BelongsToMany; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\SoftDeletes;
#[Fillable(['company_id','name','slug','description','discount_percentage','loyalty_multiplier','is_default','is_active','sort_order'])] class CustomerGroup extends Model {use SoftDeletes; protected function casts():array{return ['is_default'=>'boolean','is_active'=>'boolean'];} public function company():BelongsTo{return $this->belongsTo(Company::class);} public function members():HasMany{return $this->hasMany(CustomerGroupMember::class);} public function customers():BelongsToMany{return $this->belongsToMany(Customer::class,'customer_group_members')->withPivot(['assigned_at','assigned_by','notes'])->withTimestamps();} }
